import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(p1, p2):
        return np.sqrt(np.sum((p1 - p2) ** 2))

    def calculate_arrival_time(cur_pos, customer_pos):
        return current_time + distance(cur_pos, customer_pos) / truck_speed

    min_penalty_time = float('inf')
    best_node = None

    for idx, customer in enumerate(unvisited_customers):
        arrival_time = calculate_arrival_time(cur_truck_pos, customer)
        early_time, late_time = time_windows[idx]

        if arrival_time > late_time:
            penalty_time = arrival_time - late_time  # penalty for being late
        elif arrival_time < early_time:
            penalty_time = early_time - arrival_time  # penalize for being early, promoting waiting
        else:
            penalty_time = 0  # no penalty, within the window

        # Priority: lower penalty times and customers closer to the end of their windows
        priority_penalty = penalty_time + (late_time - arrival_time)

        if priority_penalty < min_penalty_time:
            min_penalty_time = priority_penalty
            best_node = idx

    return best_node

