def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.sqrt(np.sum((p1 - p2) ** 2))

    def calculate_travel_time(distance):
        return distance / truck_speed

    def time_until_window_close(current_time, window_end):
        return max(0, window_end - current_time)

    best_node = None
    best_node_score = float('inf')

    for idx, customer in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer)
        travel_time = calculate_travel_time(distance)
        wait_time = max(0, time_windows[idx][0] - (current_time + travel_time))
        total_time_required = current_time + travel_time + wait_time
        window_closing_time_gap = time_until_window_close(total_time_required, time_windows[idx][1])

        # Evaluation function: minimize travel_time and the risk of missing the time window
        # Additional waiting penalty: negating overly early arrivals
        score = travel_time + window_closing_time_gap + wait_time * 0.5

        if score < best_node_score:
            best_node_score = score
            best_node = idx

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(start, end):
        return np.linalg.norm(start - end) / truck_speed

    num_customers = len(unvisited_customers)
    min_penalty = float('inf')
    best_node = None

    for i in range(num_customers):
        travel_time = calculate_travel_time(cur_truck_pos, unvisited_customers[i])
        arrival_time = current_time + travel_time
        window_start, window_end = time_windows[i]

        if arrival_time < window_start:
            # Consider waiting if we arrive early
            wait_time = window_start - arrival_time
            effective_arrival_time = window_start
        else:
            wait_time = 0
            effective_arrival_time = arrival_time

        if effective_arrival_time <= window_end:
            # Calculate penalty as a function of the wait time and if we miss the middle of the window
            time_penalty = (arrival_time - (window_start + (window_end - window_start) / 2)) ** 2
            penalty = travel_time + wait_time + time_penalty

            if penalty < min_penalty:
                min_penalty = penalty
                best_node = i

        # If none is suitable and have high penalties, return None to indicate waiting may be needed
        if best_node is None and arrival_time > window_end:
            if wait_time <= (window_end - window_start) / 2:
                best_node = None
            else:
                best_node = i

    return best_node
